11	export class SpinState extends BaseState
12	{
13	    private m_gameView: GameView = null;
14	
15	    private m_isPreWinEffectPlayed: boolean = false;
16	
17	    constructor( gameView: GameView )
18	    {
19	        super();
20	        this.m_gameView = gameView;
21	    }
22	
23	    public async OnEnter()
24	    {
25	        log( "OnEnter State : SPIN" );
26	
27	        roundController.StartSpin();
28	
29	        // 清理重複秀每條線
30	        this.m_gameView.EffectPlate.CurAwardLines.length = 0;
31	        this.m_gameView.EffectPlate.StopOneLineShow();
32	
33	        // spin前清理狀態
34	        this.m_gameView.ClearAll();
35	
36	        // 清除轉輪UI效果
37	        this.ClearReelUIEffect();
38	        
39	        // 在 OnRecvSpinAck 前記錄版本，用於 CheckPreWinEffect 判斷本局 SpinAck 是否已到
40	        const prevSpinAckVersion = this.m_gameView.SpinAckVersion;
41	
42	        // BC-7：EnterFreeState 表演結束直接接 FG 第一手的連續轉動旗標，讀完即清
43	        // 註：原本此處有 await Define.Wait(0.5) 等 FlyManager 晚到 callback 完成，
44	        //   現由 EnterFreeState dispatch FLY_EVENT.CANCEL_ADD_CASH_ANIMATION 直接取消晚到 callback，不需等待
45	        const continueSpin = this.m_gameView.IsFreeGameFirstSpinContinuous;
46	        if ( continueSpin )
47	        {
48	            this.m_gameView.IsFreeGameFirstSpinContinuous = false;
49	        }
50	
51	        if ( commonGameManager.HasUnshow )
52	        {
53	            commonGameManager.HasUnshow = false;
54	            this.m_gameView.IsHardStop = newBottombarManager.IsHardStop;
55	
56	            this.m_gameView.StartSpin( undefined, continueSpin );
57	            this.m_gameView.OnRecvSpinAck( this.m_gameView.UnshowSpinAck, true );
58	            this.m_gameView.UnshowSpinAck = null;
59	        }
60	        else
61	        {
62	            // 雙層游標推進（唯一推進點）：當前局還有 plate → 推 sub；否則推局索引、sub 歸 0
63	            this.m_gameView.AdvancePlateCursor();
64	            // 重置標記僅在「換局」時（advance 後 sub===0）；Respin 續轉手（sub>0）不重置，
65	            // 避免上一手殘留誤觸 IF 分支造成 omen 重播（§6 per-手重入矩陣）
66	            if ( this.m_gameView.CurSubPlateIndex === 0 )
67	            {
68	                this.m_gameView.PreWinHandledIndex = -1;
69	            }
70	            this.m_gameView.StartSpin( undefined, continueSpin );
71	        }
72	
73	        await this.CheckPreWinEffect( prevSpinAckVersion );
74	
75	        // 宣告動畫完成後，統一設定盤面資料（含 SetPlateInfo → SetReelTimes）
76	        const nowRound = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurPlateIndex ];
77	        this.m_gameView.SetNowRoundInfo( nowRound );
78	
79	        // SetReelTimes 已執行，可安全呼叫快停
80	        if ( this.m_gameView.IsHardStop && !this.m_gameView.IsMgOmen )
81	        {
82	            this.m_gameView.SlotReels.ClickStopBtn();
83	        }
84	
85	        // FreeGame 專屬 UI 更新
86	        if ( this.m_gameView.IsFreeGame )
87	        {
88	            eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.SET_NOW_ROUND, nowRound.FreeNowRound );
89	
90	            if ( !this.m_gameView.IsHardStop && !newBottombarManager.IsAutoSpin )
91	            {
92	                newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
93	            }
94	        }
95	    }
96	
97	    public OnProcess( dt: number )
98	    {
99	        this.m_gameView.SlotReels.Spin( dt );
100	        if ( !this.m_gameView.SlotReels.IsStop || this.m_isPreWinEffectPlayed || !this.m_gameView.SlotReels.IsEntryEffectDone )
101	        {
102	            return;
103	        }
104	
105	        this.m_gameView.CanPlateStop = true;
106	        this.m_gameView.CanSpaceStop = true;
107	        if ( !newBottombarManager.IsAutoSpin )
108	        {
109	            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
110	        }
111	
112	        stateManager.NextState( Game_Define.GameState.EFFECT_START );
113	    }
114	
115	    public OnLeave()
116	    {
117	 
118	    }
119	
120	    /**
121	     * @ch 播放預中效果動畫
122	     * @param mysteryEventKind 預中類型
123	     * @returns Promise 震動效果完成的 Promise
124	     */
125	    private async PlayPreWinEffect(mysteryEventKind: number): Promise<void> {
126	        return new Promise<void>((resolve) => {
127	            eventManager.Dispatch(PRE_WIN_EVENT.PLAY_PRE_WIN_ANIM, mysteryEventKind === 1 ? PreWinType.Scatter : PreWinType.Collect, resolve);
128	        });
129	    }
130	
131	    /**
132	     * @ch 檢查預中效果動畫
133	     * @param prevSpinAckVersion OnEnter 開始前記錄的 SpinAckVersion，用於 Base Game 判斷新的 SpinAck 是否已到
134	     * @returns Promise 預中效果完成的 Promise
135	     */
136	    private async CheckPreWinEffect( prevSpinAckVersion: number ): Promise<void> {
137	        this.m_isPreWinEffectPlayed = true;
138	
139	        // Respin 續轉手（sub>0）：omen（MysteryEventKind）屬 round 級事件，每局至多播一次，
140	        // 續轉手早退不重播（§6 per-手重入矩陣）
141	        if ( this.m_gameView.CurSubPlateIndex > 0 )
142	        {
143	            this.m_isPreWinEffectPlayed = false;
144	            return;
145	        }
146	
147	        const currentIndex = this.m_gameView.CurPlateIndex;
148	
149	        if ( this.m_gameView.PreWinHandledIndex === currentIndex )
150	        {
151	            // OnRecvSpinAck 已為此 index 觸發動畫（Base Game 正常流程 / Unshow）
152	            // 直接等待該動畫結束即可
153	            await this.m_gameView.PreWinAnimPromise;
154	        }
155	        else if ( !this.m_gameView.IsFreeGame && !this.m_gameView.IsRespinGame )
156	        {
157	            // Base Game：OnRecvSpinAck 尚未到達，等待本局新的 SpinAck
158	            // 用版本號判斷，避免誤讀上一局的舊 SpinAck
159	            await WaitUntil( () => this.m_gameView.SpinAckVersion > prevSpinAckVersion );
160	            // OnRecvSpinAck 已設定 PreWinAnimPromise（有宣告時為動畫 Promise，否則為立即 resolve）
161	            await this.m_gameView.PreWinAnimPromise;
162	        }
163	        else
164	        {
165	            // FG / Respin 後續回合：SpinAck 資料已在首輪一次性到達，直接讀取
166	            if ( currentIndex < 0 )
167	            {
168	                error( "currentIndex is less than 0" );
169	            }
170	            const nowRound = this.m_gameView.SpinAck?.RoundQueue?.[ currentIndex ];
171	            if ( nowRound && nowRound.MysteryEventKind > 0 )
172	            {
173	                await this.PlayPreWinEffect( nowRound.MysteryEventKind );
174	            }
175	        }
176	
177	        this.m_isPreWinEffectPlayed = false;
178	    }
179	
180	    /**
181	     * @ch 清除轉輪UI效果
182	     */
183	    private ClearReelUIEffect()
184	    {
185	        if (!this.m_gameView.IsRespinGame)
186	        {
187	            eventManager.Dispatch(REEL_UI_EVENT.HIDE_LIGHT_LEFT_REEL);
188	            eventManager.Dispatch(REEL_UI_EVENT.HIDE_LIGHT_RIGHT_REEL);
189	        }
190	        eventManager.Dispatch(REEL_UI_EVENT.PREWIN_FRAME_FADE_OUT, -1);
191	    }
192	}

