39	        console.log( "OnEnter State: ENTER_RESPIN" );
40	
41	        // 首手 / 續轉分流：首手時 IsRespinGame 尚未設為 true
42	        const isFirstHand = !this.m_gameView.IsRespinGame;
43	
44	        if ( isFirstHand )
45	        {
46	            // 首手進場：緩衝等待 → 設 Respin 狀態 → 清盤（鎖列在 HandleReel 內處理）
47	            await Define.Wait( this.m_gameView, EnterRespinState.WAIT_TIME );
48	            this.m_gameView.IsRespinGame = true;
49	            this.m_gameView.ClearAll();
50	        }
51	
52	        // 累加本手鎖定位置 + 以累積集合冪等重建靜態圖（首手與續轉同邏輯）
53	        this.HandleReel();
54	
55	        // 宣告動畫：可開關，僅首手且開關開啟時播（預設不播，續轉手一律不播）
