86	            this.m_gameView.SlotReels.SetColumnLock( column, true );
87	        } );
88	
89	        // 讀「剛播完那手」的鎖定位置（server 增量），解碼後累加進 GameView 累積集合
90	        const plate = this.m_gameView.RoundInfo?.PlateQueue?.[ this.m_gameView.CurSubPlateIndex ];
91	        const { entries, warnings } = ResolveLockedEntries(
92	            plate?.PlateSymbol,
93	            plate?.RespinLockedPos,
94	            Common.DecodeServerPosByRowConfig
95	        );
96	        warnings.forEach( w => console.warn( `[EnterRespinState] ${w}` ) );
97	        this.m_gameView.MergeRespinLocks( entries );
98	
99	        // 以「累積集合」全量冪等重建靜態圖——續轉手不依賴前一手演出殘留，可重入
100	        this.m_gameView.RespinLockedSet.forEach( entry =>
101	        {
102	            const { col, row, symbol, number } = entry;
103	
104	            // col 0/5 已由 SetColumnLock 整輪鎖定（符號留存）；開關開啟時略過 EffectPlate 靜態張重建
105	            if ( EnterRespinState.EXCLUDE_LOCK_COLUMNS_FROM_STATIC
106	                && Game_Define.RespinLockColumns.includes( col ) )
107	            {
108	                return;
109	            }
110	
111	            // CollectAndRetrigger 在 Respin 鎖定時顯示為 Collect 靜態張
112	            const displaySymbol = ( symbol === Game_Define.Symbol.CollectAndRetrigger )
113	                ? Game_Define.Symbol.Collect
114	                : symbol;
115	
116	            // 清掉該位置殘留的 Spine 節點（停輪時建立的），避免蓋住靜態張
117	            this.m_gameView.EffectPlate.CleanSymbolSpineAt( col, row, Game_Define.LAYERS.TWO, false );
118	
119	            // 關閉原本格子的靜態圖，改用 EffectPlate 疊一張靜態圖
120	            this.m_gameView.SlotReels.AllColumns?.[ Game_Define.MIDDLE_PLATE_INDEX ]?.[ col ]?.HideSymbolByRow( row );
121	            this.m_gameView.EffectPlate.CreateSymbolStaticNode( col, row, displaySymbol, number );
122	        } );
123	    }
