9	@ccclass( "CheckState" )
10	export class CheckState extends BaseState
11	{
12	    private m_gameView: GameView = null;
13	
14	    constructor( gameView: GameView )
15	    {
16	        super();
17	        this.m_gameView = gameView;
18	    }
19	
20	    public async OnEnter()
21	    {
22	        log( "OnEnter state : CHECK_STATE" );
23	        
24	        // 優先序重排（v2）：plate 內循環（Respin）優先於換局，繞過 ROUND_END。
25	        // 旗標改唯讀 getter，不再賦值清除（CurPlateIndex/CurSubPlateIndex 推進後 getter 自動翻轉）。
26	
27	        // ① 當前局還有未播 plate → 首手與連鎖續轉同路徑（ENTER_RESPIN 之後 → SPIN 播下一手）
28	        if ( this.m_gameView.IsGoingToRespinGame )
29	        {
30	            stateManager.NextState( Game_Define.GameState.ENTER_RESPIN );
31	        }
32	        // ② 在 Respin 中且 plate 已用盡（①不成立 ⇒ 必已播完）→ 離開 Respin
33	        else if ( this.m_gameView.IsRespinGame )
34	        {
35	            stateManager.NextState( Game_Define.GameState.LEAVE_RESPIN );
36	        }
37	        // ③ MainGame 局結束要進 FreeGame
38	        else if ( this.m_gameView.IsGoingToFree )
39	        {
40	            stateManager.NextState( Game_Define.GameState.ENTER_FREE );
41	        }
42	        // ④ FreeGame 最後一局 → 離開 FG
43	        else if (
44	            this.m_gameView.IsFreeGame
45	            && this.m_gameView.CurPlateIndex + 1 === this.m_gameView.SpinAck.RoundQueue.length
46	        )
47	        {
48	            stateManager.NextState( Game_Define.GameState.LEAVE_FREE );
49	        }
50	        // ⑤ 一般局結束（RoundInfo 級 ROUND_END，ReqRoundEnd 一次）
51	        else
52	        {
53	            stateManager.NextState( Game_Define.GameState.ROUND_END );
54	        }
55	    }
